public class PowerOfThree {
    public static boolean isPowerOfThree(int n) {
        return isPowerOfThree(n, 1);
    }

    private static boolean isPowerOfThree(int n, int x) {
        if (n == 0 || n == 1) {
            return n == 1;
        }

        if (n % 3 == 0 && n != 3) {
            return true;
        }

        if (n % 3 == 1) {
